import { defineComponentSlotStyle } from "@yamada-ui/react"

export const stepsStyle = defineComponentSlotStyle({
  base: {
    description: {
      color: "fg.muted",
    },
    indicator: {
      alignItems: "center",
      boxSize: "{size}",
      display: "flex",
      flexShrink: "0",
      fontWeight: "medium",
      justifyContent: "center",
      rounded: "full",
      transitionDuration: "moderate",
      transitionProperty: "common",
    },
    item: {
      display: "flex",
      flex: "1 0 0",
      position: "relative",
      _last: {
        "& [role=separator]": {
          display: "none",
        },
        flex: "initial",
      },
    },
    list: {
      display: "flex",
      gap: "3",
      justifyContent: "space-between",
    },
    root: {
      display: "flex",
      gap: "4",
      w: "full",
    },
    separator: {
      bg: "border",
      flex: "1",
      transitionDuration: "moderate",
      transitionProperty: "common",
    },
    title: {
      fontWeight: "medium",
    },
  },

  props: {
    /**
     * The orientation of the steps.
     *
     * @default 'horizontal'
     */
    orientation: {
      horizontal: {
        item: {
          alignItems: "center",
          flexDirection: "row",
        },
        list: {
          alignItems: "center",
          flexDirection: "row",
          w: "full",
        },
        root: {
          flexDirection: "column",
        },
        separator: {
          h: "{thickness}",
          w: "full",
        },
      },
      vertical: {
        content: {
          flex: "1",
        },
        item: {
          alignItems: "flex-start",
        },
        list: {
          alignItems: "flex-start",
          flexDirection: "column",
        },
        root: {
          flexDirection: "row",
        },
        separator: {
          h: "full",
          insetBlockStart: "calc({size} + {gap})",
          insetInlineStart: "calc(({size} / 2) - ({thickness} / 2))",
          maxH: `calc(full - {size} - {gap})`,
          position: "absolute",
          w: "{thickness}",
        },
      },
    },
  },

  variants: {
    solid: {
      indicator: {
        _complete: {
          layerStyle: "solid",
        },
        _current: {
          bg: "colorScheme.muted",
          color: "colorScheme.fg",
        },
        _incomplete: {
          bg: "bg.subtle",
          color: "fg.emphasized",
        },
      },
      separator: {
        _complete: {
          bg: "colorScheme.solid",
        },
      },
    },
    subtle: {
      indicator: {
        _complete: {
          bg: "colorScheme.emphasized",
          color: "colorScheme.fg",
        },
        _current: {
          bg: "colorScheme.muted",
          color: "colorScheme.fg",
        },
        _incomplete: {
          bg: "bg.subtle",
          color: "fg.emphasized",
        },
      },
      separator: {
        _complete: {
          bg: "colorScheme.emphasized",
        },
      },
    },
  },

  sizes: {
    sm: {
      indicator: {
        fontSize: "md",
      },
      item: {
        "--gap": "sizes.3",
        "--size": "sizes.8",
        "--thickness": "sizes.0.5",
        fontSize: "xs",
        gap: "3",
      },
    },
    md: {
      indicator: {
        fontSize: "md",
      },
      item: {
        "--gap": "sizes.3",
        "--size": "sizes.10",
        "--thickness": "sizes.0.5",
        fontSize: "sm",
        gap: "3",
      },
    },
    lg: {
      indicator: {
        fontSize: "lg",
      },
      item: {
        "--gap": "sizes.3",
        "--size": "sizes.12",
        "--thickness": "sizes.0.5",
        gap: "3",
      },
    },
  },

  defaultProps: {
    size: "md",
    variant: "solid",
    orientation: "horizontal",
  },
})

export type StepsStyle = typeof stepsStyle

import type { FC } from "react"
import { useMemo } from "react"
import { a11y, page, render } from "#test/browser"
import { Steps } from "."
import { ButtonGroup } from "../button"
import { useSteps, useStepsItem } from "./use-steps"

interface TestComponentProps extends Steps.RootProps {
  itemProps?: Required<Steps.RootProps>["items"][number]
}

const TestComponent: FC<TestComponentProps> = ({ itemProps, ...rest }) => {
  const items: Steps.Item[] = useMemo(
    () =>
      [
        {
          content:
            "地球の人里離れた山奥に住む尻尾の生えた少年・孫悟空はある日、西の都からやって来た少女・ブルマと出会う。そこで、7つ集めると神龍（シェンロン）が現れ、どんな願いでも一つだけ叶えてくれるというドラゴンボールの存在を、さらに育ての親である孫悟飯の形見として大切に持っていた球がその1つ「四星球（スーシンチュウ）」であることを知り、ブルマと共に残りのドラゴンボールを探す旅に出る。",
          description: "レッドリボン軍",
          title: "孫悟空少年編",
        },
        {
          content:
            "天下一武道会終了後、ピラフ一味によって復活したピッコロ大魔王によって、クリリンや亀仙人など悟空の仲間たちや多くの武道家たちが殺される。悟空は仇を討つため、道中に出会ったヤジロベーや仙猫カリンの協力を得て命を賭して潜在する力を引き出し、ピッコロ大魔王に闘いを挑み勝利する。闘いの後、悟空はピッコロ大魔王に殺された神龍や仲間たちの復活のため天界へ向かい、ドラゴンボールの創造者である神に会う。そこで神龍復活の条件として、神の下で天界で修行することとなった。",
          description: "ピッコロ大魔王",
          title: "ピッコロ大魔王編",
        },
        {
          content:
            "ピッコロ（マジュニア）との闘いから約5年後、息子の孫悟飯を儲けて平和な日々を過ごしていた悟空のもとに、実兄・ラディッツが宇宙より来襲し、自分が惑星ベジータの戦闘民族・サイヤ人であることを知らされる。さらわれた孫悟飯を助けるため悟空は宿敵ピッコロと手を組み、自らの命と引き換えにラディッツを倒すが、約1年後にはさらに強力なサイヤ人たちがドラゴンボールを求めて地球に来襲することを知る。",
          description: "ベジータ・ナッパ",
          title: "サイヤ人編",
        },
      ].map((item) => ({ ...item, ...itemProps })),
    [itemProps],
  )

  return (
    <Steps.Root data-testid="root" items={items} {...rest}>
      <Steps.List />
      <Steps.Contents />
      <Steps.CompletedContent data-testid="completedContent">
        地球の神と殺された仲間たちを甦らせるため、重傷で入院中の悟空に代わり、悟飯、クリリン、ブルマの3人が神とピッコロの故郷であるナメック星へ向かう。だが、そこには地球で闘ったベジータや、界王すら畏怖する宇宙の帝王・フリーザとその一味が不老不死を求めて来襲し、ナメック星人を虐殺しながらドラゴンボールを略奪していた。悟飯たちはベジータ、フリーザ一味とのドラゴンボールをめぐる三つ巴の攻防の末、後から到着した悟空とナメック星人たちの協力を得てナメック星の神龍・ポルンガを呼び出し、ピッコロと地球のドラゴンボールを復活させる。
      </Steps.CompletedContent>

      <ButtonGroup.Root>
        <Steps.PrevTrigger>
          <ButtonGroup.Item>Prev</ButtonGroup.Item>
        </Steps.PrevTrigger>
        <Steps.NextTrigger>
          <ButtonGroup.Item>Next</ButtonGroup.Item>
        </Steps.NextTrigger>
      </ButtonGroup.Root>
    </Steps.Root>
  )
}

describe("<Stepper />", () => {
  test("renders component correctly", async () => {
    await a11y(<TestComponent />)
  })

  test("sets `displayName` correctly", () => {
    expect(Steps.Root.displayName).toBe("StepsRoot")
    expect(Steps.List.displayName).toBe("StepsList")
    expect(Steps.Item.displayName).toBe("StepsItem")
    expect(Steps.Indicator.displayName).toBe("StepsIndicator")
    expect(Steps.Number.displayName).toBe("StepsNumber")
    expect(Steps.Title.displayName).toBe("StepsTitle")
    expect(Steps.Description.displayName).toBe("StepsDescription")
    expect(Steps.Separator.displayName).toBe("StepsSeparator")
    expect(Steps.Contents.name).toBe("StepsContents")
    expect(Steps.Content.displayName).toBe("StepsContent")
    expect(Steps.CompletedContent.displayName).toBe("StepsCompletedContent")
  })

  test("sets `className` correctly", async () => {
    await render(<TestComponent />)
    const root = page.getByTestId("root")
    const rootElement = root.element()

    await expect.element(root).toHaveClass("ui-steps__root")
    await expect.element(page.getByRole("list")).toHaveClass("ui-steps__list")
    await expect
      .element(page.getByRole("listitem").first())
      .toHaveClass("ui-steps__item")
    await expect
      .element(page.getByRole("heading").first())
      .toHaveClass("ui-steps__title")
    await expect
      .element(page.getByRole("paragraph").first())
      .toHaveClass("ui-steps__description")
    await expect
      .element(page.getByRole("separator").first())
      .toHaveClass("ui-steps__separator")
    expect(rootElement.children[1]).toHaveClass("ui-steps__content")
    await expect
      .element(page.getByTestId("completedContent"))
      .toHaveClass("ui-steps__content--completed")
    await expect
      .element(page.getByRole("button", { name: /Prev/i }))
      .toHaveClass("ui-steps__trigger--prev")
    await expect
      .element(page.getByRole("button", { name: /Next/i }))
      .toHaveClass("ui-steps__trigger--next")
  })

  test("renders HTML tag correctly", async () => {
    await render(<TestComponent />)
    const root = page.getByTestId("root").element()
    expect(root.tagName).toBe("DIV")
    expect(page.getByRole("list").element().tagName).toBe("OL")
    expect(page.getByRole("listitem").first().element().tagName).toBe("LI")
    expect(page.getByRole("heading").first().element().tagName).toBe("H3")
    expect(page.getByRole("paragraph").first().element().tagName).toBe("P")
    expect(page.getByRole("separator").first().element().tagName).toBe("DIV")
    expect(root.children[1]?.tagName).toBe("DIV")
    expect(page.getByTestId("completedContent").element().tagName).toBe("DIV")
    expect(page.getByRole("button", { name: /Prev/i }).element().tagName).toBe(
      "BUTTON",
    )
    expect(page.getByRole("button", { name: /Next/i }).element().tagName).toBe(
      "BUTTON",
    )
  })

  test("merges root props correctly in `useSteps.getRootProps`", async () => {
    const hookRef = vi.fn()
    const getterRef = vi.fn()
    const hookClick = vi.fn()
    const getterClick = vi.fn()

    const UseStepsRootProbe = () => {
      const { getRootProps } = useSteps({
        ref: hookRef,
        className: "hook-root",
        style: { padding: "1px" },
        onClick: hookClick,
      })

      return (
        <div
          data-testid="use-steps-root"
          {...getRootProps({
            ref: getterRef,
            className: "getter-root",
            style: { margin: "2px" },
            onClick: getterClick,
          })}
        />
      )
    }

    const { user } = await render(<UseStepsRootProbe />)

    const root = page.getByTestId("use-steps-root").element()

    expect(root).toHaveClass("hook-root")
    expect(root).toHaveClass("getter-root")
    expect(root).toHaveStyle({ padding: "1px" })
    expect(root).toHaveStyle({ margin: "2px" })

    await user.click(root)

    expect(hookRef).toHaveBeenCalledWith(root)
    expect(getterRef).toHaveBeenCalledWith(root)
    expect(hookClick).toHaveBeenCalledTimes(1)
    expect(getterClick).toHaveBeenCalledTimes(1)
  })

  test("merges item props correctly in `useStepsItem.getRootProps`", async () => {
    const hookRef = vi.fn()
    const getterRef = vi.fn()
    const hookClick = vi.fn()
    const getterClick = vi.fn()

    const UseStepsItemProbe = () => {
      const { getRootProps } = useStepsItem({
        ref: hookRef,
        className: "hook-item",
        style: { padding: "1px" },
        index: 0,
        onClick: hookClick,
      })

      return (
        <li
          data-testid="use-steps-item"
          {...getRootProps({
            ref: getterRef,
            className: "getter-item",
            style: { margin: "2px" },
            onClick: getterClick,
          })}
        />
      )
    }

    const { user } = await render(
      <Steps.Root>
        <UseStepsItemProbe />
      </Steps.Root>,
    )

    const item = page.getByTestId("use-steps-item").element()

    expect(item).toHaveClass("hook-item")
    expect(item).toHaveClass("getter-item")
    expect(item).toHaveStyle({ padding: "1px" })
    expect(item).toHaveStyle({ margin: "2px" })

    await user.tab()
    await user.click(item)

    expect(hookRef).toHaveBeenCalledWith(item)
    expect(getterRef).toHaveBeenCalledWith(item)
    expect(hookClick).toHaveBeenCalledTimes(1)
    expect(getterClick).toHaveBeenCalledTimes(1)
  })
})

"use client"

import type { FC, PropsWithChildren, ReactNode } from "react"
import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { UseLazyMountProps } from "../../hooks/use-lazy-mount"
import type { StepsStyle } from "./steps.style"
import type { UseStepsItemProps, UseStepsProps } from "./use-steps"
import { Children, useMemo } from "react"
import { createSlotComponent, styled, isNull,
  isUndefined,
  useFindChild,
  useValidChildren, } from "@yamada-ui/react"
import { useLazyMount } from "../../hooks/use-lazy-mount"
import { useValue } from "../../hooks/use-value"
import { CheckIcon } from "../icon"
import { stepsStyle } from "./steps.style"
import {
  StepsContext,
  StepsDescendantsContext,
  StepsItemContext,
  useSteps,
  useStepsContext,
  useStepsItem,
  useStepsItemContext,
} from "./use-steps"

interface ComponentContext extends Pick<
  StepsRootProps,
  "items" | "lazy" | "lazyBehavior"
> {}

export interface StepsItem
  extends
    Omit<StepsItemProps, "content" | "index" | "title">,
    Pick<StepsIndicatorProps, "complete" | "current" | "incomplete"> {
  /**
   * The content for step element.
   */
  content?: ReactNode
  /**
   * The description for step element.
   */
  description?: ReactNode
  /**
   * If true, display the step separator.
   *
   * @default true
   */
  hasSeparator?: boolean
  /**
   * The title for step element.
   */
  title?: string
  /**
   * Props for step content element.
   */
  contentProps?: StepsContentProps
  /**
   * Props for step description element.
   */
  descriptionProps?: StepsDescriptionProps
  /**
   * Props for step indicator element.
   */
  indicatorProps?: StepsIndicatorProps
  /**
   * Props for step separator element.
   */
  separatorProps?: StepsSeparatorProps
  /**
   * Props for step title element.
   */
  titleProps?: StepsTitleProps
}

export interface StepsRootProps
  extends
    Omit<HTMLStyledProps, "onChange">,
    Omit<UseStepsProps, "count" | "orientation">,
    Pick<UseLazyMountProps, "lazy" | "lazyBehavior">,
    ThemeProps<StepsStyle> {
  /**
   * If provided, generate step components based on steps.
   */
  items?: StepsItem[]
}

const {
  ComponentContext,
  PropsContext: StepsPropsContext,
  useComponentContext,
  usePropsContext: useStepsPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<StepsRootProps, StepsStyle, ComponentContext>(
  "steps",
  stepsStyle,
)

export { StepsPropsContext, useStepsPropsContext }

/**
 * `Steps` is a component that displays the progress of a multi-step process.
 *
 * @see https://yamada-ui.com/docs/components/steps
 */
export const StepsRoot = withProvider<"div", StepsRootProps, "orientation">(
  ({
    children,
    items = [],
    lazy,
    lazyBehavior,
    orientation: orientationProp,
    ...rest
  }) => {
    const computedOrientation = useValue(orientationProp)
    const validChildren = useValidChildren(children)
    const stepsList = useFindChild<StepsListProps>(validChildren, StepsList)
    const {
      id,
      count,
      descendants,
      getStatus,
      index,
      orientation,
      setIndex,
      getContentProps,
      getListProps,
      getNextTriggerProps,
      getPrevTriggerProps,
      getRootProps,
      onNext,
      onPrev,
    } = useSteps({
      count: items.length || Children.count(stepsList?.props.children),
      orientation: computedOrientation,
      ...rest,
    })
    const componentContext = useMemo(
      () => ({ items, lazy, lazyBehavior }),
      [items, lazy, lazyBehavior],
    )
    const stepsContext = useMemo(
      () => ({
        id,
        count,
        getStatus,
        index,
        orientation,
        setIndex,
        getContentProps,
        getListProps,
        getNextTriggerProps,
        getPrevTriggerProps,
        onNext,
        onPrev,
      }),
      [
        id,
        count,
        index,
        orientation,
        setIndex,
        getStatus,
        onNext,
        onPrev,
        getListProps,
        getNextTriggerProps,
        getPrevTriggerProps,
        getContentProps,
      ],
    )

    return (
      <StepsDescendantsContext value={descendants}>
        <StepsContext value={stepsContext}>
          <ComponentContext value={componentContext}>
            <styled.div {...getRootProps()}>{children}</styled.div>
          </ComponentContext>
        </StepsContext>
      </StepsDescendantsContext>
    )
  },
  "root",
  { transferProps: ["orientation"] },
)()

export interface StepsListProps extends HTMLStyledProps<"ol"> {}

export const StepsList = withContext<"ol", StepsListProps>(
  ({ children, ...rest }) => {
    const { items } = useComponentContext()
    const { getListProps } = useStepsContext()
    const computedChildren = useMemo(() => {
      if (children) {
        return children
      } else {
        return items?.map(
          (
            {
              complete,
              content: _content,
              current,
              description,
              hasSeparator = true,
              incomplete,
              title,
              contentProps: _contentProps,
              descriptionProps,
              indicatorProps,
              separatorProps,
              titleProps,
              ...rest
            },
            index,
          ) => (
            <StepsItem key={index} index={index} title={title} {...rest}>
              <StepsIndicator
                complete={complete}
                current={current}
                incomplete={incomplete}
                {...indicatorProps}
              />

              <styled.div>
                {title ? (
                  <StepsTitle {...titleProps}>{title}</StepsTitle>
                ) : null}
                {description ? (
                  <StepsDescription {...descriptionProps}>
                    {description}
                  </StepsDescription>
                ) : null}
              </styled.div>

              {hasSeparator ? <StepsSeparator {...separatorProps} /> : null}
            </StepsItem>
          ),
        )
      }
    }, [children, items])

    return <styled.ol {...getListProps(rest)}>{computedChildren}</styled.ol>
  },
  "list",
)()

export interface StepsItemProps
  extends HTMLStyledProps<"li">, UseStepsItemProps {}

export const StepsItem = withContext<"li", StepsItemProps>((props) => {
  const {
    first,
    index,
    last,
    status,
    getDescriptionProps,
    getIndicatorProps,
    getRootProps,
    getSeparatorProps,
    getTitleProps,
  } = useStepsItem(props)
  const context = useMemo(
    () => ({
      first,
      index,
      last,
      status,
      getDescriptionProps,
      getIndicatorProps,
      getSeparatorProps,
      getTitleProps,
    }),
    [
      first,
      index,
      last,
      status,
      getTitleProps,
      getDescriptionProps,
      getSeparatorProps,
      getIndicatorProps,
    ],
  )

  return (
    <StepsItemContext value={context}>
      <styled.li {...getRootProps()} />
    </StepsItemContext>
  )
}, "item")()

export interface StepsIndicatorProps extends HTMLStyledProps {
  /**
   * The element for the complete indicator.
   *
   * @default <CheckIcon />
   */
  complete?: ReactNode
  /**
   * The element for the current indicator.
   *
   * @default <StepsNumber />
   */
  current?: ReactNode
  /**
   * The element for the incomplete indicator.
   *
   * @default <StepsNumber />
   */
  incomplete?: ReactNode
}

export const StepsIndicator = withContext<"div", StepsIndicatorProps>(
  ({
    complete = <CheckIcon />,
    current = <StepsNumber />,
    incomplete = <StepsNumber />,
    ...rest
  }) => {
    const { status, getIndicatorProps } = useStepsItemContext()
    const components = useMemo(
      () => ({ complete, current, incomplete }),
      [complete, current, incomplete],
    )

    return (
      <styled.div {...getIndicatorProps(rest)}>{components[status]}</styled.div>
    )
  },
  "indicator",
)()

export interface StepsNumberProps extends HTMLStyledProps<"span"> {}

export const StepsNumber = withContext<"span", StepsNumberProps>(
  "span",
  "number",
)(undefined, ({ children, ...rest }) => {
  const { index } = useStepsItemContext()

  return { ...rest, children: children ?? index + 1 }
})

export interface StepsTitleProps extends HTMLStyledProps {}

export const StepsTitle = withContext<"h3", StepsTitleProps>("h3", "title")(
  undefined,
  (props) => {
    const { getTitleProps } = useStepsItemContext()

    return getTitleProps(props)
  },
)

export interface StepsDescriptionProps extends HTMLStyledProps<"p"> {}

export const StepsDescription = withContext<"p", StepsDescriptionProps>(
  "p",
  "description",
)(undefined, (props) => {
  const { getDescriptionProps } = useStepsItemContext()

  return getDescriptionProps(props)
})

export interface StepsSeparatorProps extends HTMLStyledProps {}

export const StepsSeparator = withContext<"div", StepsSeparatorProps>(
  "div",
  "separator",
)(undefined, (props) => {
  const { getSeparatorProps } = useStepsItemContext()

  return getSeparatorProps(props)
})

export interface StepsContentsProps extends PropsWithChildren {}

export const StepsContents: FC<StepsContentsProps> = ({ children }) => {
  const { items } = useComponentContext()

  return useMemo(() => {
    if (children) {
      return children
    } else {
      return items?.map(({ content, contentProps }, index) =>
        isUndefined(content) || isNull(content) ? null : (
          <StepsContent key={index} index={index} {...contentProps}>
            {content}
          </StepsContent>
        ),
      )
    }
  }, [children, items])
}

export interface StepsContentProps extends HTMLStyledProps {
  /**
   * The index of the step content.
   */
  index: number
}

export const StepsContent = withContext<"div", StepsContentProps>(
  "div",
  "content",
)(undefined, ({ index, ...rest }) => {
  const { lazy, lazyBehavior } = useComponentContext()
  const { index: selectedIndex, getContentProps } = useStepsContext()
  const mounted = index === selectedIndex
  const children = useLazyMount({
    lazy,
    lazyBehavior,
    mounted,
    ...rest,
  })

  return { ...getContentProps({ index, ...rest }), children }
})

export interface StepsCompletedContentProps extends HTMLStyledProps {}

export const StepsCompletedContent = withContext<
  "div",
  StepsCompletedContentProps
>("div", { name: "CompletedContent", slot: ["content", "completed"] })(
  undefined,
  (props) => {
    const { lazy, lazyBehavior } = useComponentContext()
    const { count, index: selectedIndex, getContentProps } = useStepsContext()
    const mounted = count !== 0 && count === selectedIndex
    const children = useLazyMount({
      lazy,
      lazyBehavior,
      mounted,
      ...props,
    })

    return { ...getContentProps(props), children }
  },
)

export interface StepsPrevTriggerProps extends HTMLStyledProps<"button"> {}

export const StepsPrevTrigger = withContext<"button", StepsPrevTriggerProps>(
  "button",
  { name: "PrevTrigger", slot: ["trigger", "prev"] },
)((props) => {
  const { getPrevTriggerProps } = useStepsContext()

  return { asChild: true, ...getPrevTriggerProps(props) }
})

export interface StepsNextTriggerProps extends HTMLStyledProps<"button"> {}

export const StepsNextTrigger = withContext<"button", StepsNextTriggerProps>(
  "button",
  { name: "NextTrigger", slot: ["trigger", "next"] },
)((props) => {
  const { getNextTriggerProps } = useStepsContext()

  return { asChild: true, ...getNextTriggerProps(props) }
})

"use client"

import type { HTMLProps, Orientation, PropGetter } from "@yamada-ui/react"
import { useCallback, useId } from "react"
import {
  mergeProps,
  useEnvironment,
  createContext,
  cx,
  dataAttr,
  handlerAll,
  mergeRefs,
  setAttribute,
  useSafeLayoutEffect,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { createDescendants } from "../../hooks/use-descendants"

export type StepStatusScheme = "complete" | "current" | "incomplete"

const {
  DescendantsContext: StepsDescendantsContext,
  useDescendant: useStepsDescendant,
  useDescendants: useStepsDescendants,
} = createDescendants<HTMLLIElement>()

export { StepsDescendantsContext, useStepsDescendant, useStepsDescendants }

interface StepsContext extends Omit<
  UseStepsReturn,
  "descendants" | "getRootProps"
> {}

const [StepsContext, useStepsContext] = createContext<StepsContext>({
  name: "StepsContext",
})

export { StepsContext, useStepsContext }

interface StepsItemContext extends Omit<UseStepsItemReturn, "getRootProps"> {}

const [StepsItemContext, useStepsItemContext] = createContext<StepsItemContext>(
  {
    name: "StepsItemContext",
  },
)

export { StepsItemContext, useStepsItemContext }

export interface UseStepsProps extends Omit<HTMLProps, "onChange"> {
  /**
   * The total number of steps.
   */
  count?: number
  /**
   * The initial index of the active step.
   *
   * @default 0
   */
  defaultIndex?: number
  /**
   * The index of the active step.
   */
  index?: number
  /**
   * The orientation of the steps.
   *
   * @default 'horizontal'
   */
  orientation?: Orientation
  /**
   * The callback function that is called when the active step index is changed.
   */
  onChange?: (index: number) => void
}

export const useSteps = ({
  count = 0,
  defaultIndex = 0,
  index: indexProp,
  orientation = "horizontal",
  onChange,
  ...rest
}: UseStepsProps = {}) => {
  const descendants = useStepsDescendants()
  const [index, setIndex] = useControllableState({
    defaultValue: defaultIndex,
    value: indexProp,
    onChange,
  })
  const id = useId()

  const getStatus = useCallback(
    (indexProp: number): StepStatusScheme => {
      if (indexProp < index) {
        return "complete"
      } else if (indexProp > index) {
        return "incomplete"
      } else {
        return "current"
      }
    },
    [index],
  )

  const onPrev = useCallback(
    () => setIndex((index) => Math.max(0, index - 1)),
    [setIndex],
  )

  const onNext = useCallback(() => {
    setIndex((index) => Math.min(count, index + 1))
  }, [count, setIndex])

  const getRootProps: PropGetter = useCallback(
    (props = {}) => mergeProps(rest, props)(),
    [rest],
  )

  const getListProps: PropGetter<"ol"> = useCallback(
    (props) => {
      return {
        "data-orientation": orientation,
        ...props,
      }
    },
    [orientation],
  )

  const getContentProps: PropGetter<"div", { index?: number }> = useCallback(
    ({ index: indexProp = count, ...props } = {}) => ({
      id: `${id}-${indexProp}`,
      hidden: indexProp !== index,
      tabIndex: 0,
      ...props,
    }),
    [count, id, index],
  )

  const getPrevTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => ({
      disabled: index === 0,
      ...props,
      onClick: handlerAll(props.onClick, onPrev),
    }),
    [onPrev, index],
  )

  const getNextTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => {
      return {
        disabled: count <= index,
        ...props,
        onClick: handlerAll(props.onClick, onNext),
      }
    },
    [count, index, onNext],
  )

  return {
    id,
    count,
    descendants,
    getStatus,
    index,
    orientation,
    setIndex,
    getContentProps,
    getListProps,
    getNextTriggerProps,
    getPrevTriggerProps,
    getRootProps,
    onNext,
    onPrev,
  }
}

export type UseStepsReturn = ReturnType<typeof useSteps>

export interface UseStepsItemProps extends HTMLProps<"li"> {
  /**
   * The index of the step.
   */
  index: number
}

export const useStepsItem = ({
  "aria-labelledby": ariaLabelledbyProp,
  index,
  ...rest
}: UseStepsItemProps) => {
  const { descendants, register } = useStepsDescendant()
  const { id, getStatus, orientation } = useStepsContext()
  const status = getStatus(index)
  const current = status === "current"
  const first = index === 0
  const last = index === descendants.lastValue()?.index
  const statusDataAttr = `data-${status}`
  const { getDocument } = useEnvironment()

  useSafeLayoutEffect(() => {
    const el = descendants.value(index)?.node
    const hasContent = !!getDocument()?.getElementById(`${id}-${index}`)

    if (el && hasContent) setAttribute(el, "aria-labelledby", `${id}-${index}`)
  }, [descendants, getDocument, id, index])

  const getRootProps: PropGetter<"li"> = useCallback(
    ({ ref, "aria-labelledby": ariaLabelledby, ...props } = {}) =>
      mergeProps(
        {
          "aria-current": current ? "step" : undefined,
          "aria-labelledby": cx(ariaLabelledbyProp, ariaLabelledby),
          "data-orientation": orientation,
          [statusDataAttr]: dataAttr(true),
        },
        rest,
        props,
        { ref: mergeRefs(ref, register) },
      )(),
    [ariaLabelledbyProp, current, orientation, statusDataAttr, rest, register],
  )

  const getTitleProps: PropGetter<"h3"> = useCallback(
    (props) => ({
      [statusDataAttr]: dataAttr(true),
      ...props,
    }),
    [statusDataAttr],
  )

  const getDescriptionProps: PropGetter<"p"> = useCallback(
    (props) => ({
      [statusDataAttr]: dataAttr(true),
      ...props,
    }),
    [statusDataAttr],
  )

  const getIndicatorProps: PropGetter = useCallback(
    (props) => ({
      [statusDataAttr]: dataAttr(true),
      ...props,
    }),
    [statusDataAttr],
  )

  const getSeparatorProps: PropGetter = useCallback(
    (props) => ({
      "data-orientation": orientation,
      role: "separator",
      [statusDataAttr]: dataAttr(true),
      ...props,
    }),
    [orientation, statusDataAttr],
  )

  return {
    first,
    index,
    last,
    status,
    getDescriptionProps,
    getIndicatorProps,
    getRootProps,
    getSeparatorProps,
    getTitleProps,
  }
}

export type UseStepsItemReturn = ReturnType<typeof useStepsItem>
